#include <stdio.h>
#include <math.h>

/*
 * Basic Performance Equation: CPU Time = (Instruction Count × CPI) / Clock Rate
 * Or: CPU Time = Instruction Count × CPI × Clock Cycle Time
 */

// Calculate CPU time using clock rate (in Hz)
double calculate_cpu_time_rate(double instruction_count, double cpi, double clock_rate_hz) {
 return (instruction_count * cpi) / clock_rate_hz;
}

// Calculate CPU time using clock cycle time (in seconds)
double calculate_cpu_time_cycle(double instruction_count, double cpi, double cycle_time_sec) {
 return instruction_count * cpi * cycle_time_sec;
}

// Compare two processors and print detailed analysis
void compare_processors(double ic, double cpi_a, double rate_a, double cpi_b, double rate_b) {
 double time_a = calculate_cpu_time_rate(ic, cpi_a, rate_a);
 double time_b = calculate_cpu_time_rate(ic, cpi_b, rate_b);

 printf("\n=== CPU Performance Comparison ===\n");
 printf("Instruction Count: %.0f instructions\n\n", ic);

 printf("Processor A:\n");
 printf(" Clock Rate: %.1f GHz\n", rate_a / 1e9);
 printf(" CPI: %.1f\n", cpi_a);
 printf(" CPU Time: %.6f seconds (%.4f ms)\n\n", time_a, time_a * 1000);

 printf("Processor B:\n");
 printf(" Clock Rate: %.1f GHz\n", rate_b / 1e9);
 printf(" CPI: %.1f\n", cpi_b);
 printf(" CPU Time: %.6f seconds (%.4f ms)\n\n", time_b, time_b * 1000);

 // Determine winner
 if (time_a < time_b) {
 double speedup = time_b / time_a;
 printf("Result: Processor A is faster by %.2fx\n", speedup);
 } else if (time_b < time_a) {
 double speedup = time_a / time_b;
 printf("Result: Processor B is faster by %.2fx\n", speedup);
 } else {
 printf("Result: Both processors have EQUAL performance!\n");
 }
}

// Calculate weighted average CPI
double calculate_weighted_cpi(double ic, double cpi_values[], double ic_distribution[], int num_types) {
 double total_cycles = 0.0;
 double total_ic = 0.0;

 for (int i = 0; i < num_types; i++) {
 total_cycles += ic_distribution[i] * cpi_values[i];
 total_ic += ic_distribution[i];
 }

 return total_cycles / total_ic;
}

// Analyze performance bottlenecks
void analyze_bottleneck(double ic, double cpi, double clock_rate) {
 double cpu_time = calculate_cpu_time_rate(ic, cpi, clock_rate);

 printf("\n=== Performance Bottleneck Analysis ===\n");
 printf("Current Configuration:\n");
 printf(" Instruction Count: %.0f\n", ic);
 printf(" CPI: %.2f\n", cpi);
 printf(" Clock Rate: %.2f GHz\n", clock_rate / 1e9);
 printf(" Total CPU Time: %.6f seconds\n\n", cpu_time);

 // Calculate impact of reducing each factor by 10%
 double new_ic_time = calculate_cpu_time_rate(ic * 0.9, cpi, clock_rate);
 double new_cpi_time = calculate_cpu_time_rate(ic, cpi * 0.9, clock_rate);
 double new_rate_time = calculate_cpu_time_rate(ic, cpi, clock_rate * 1.1);

 printf("Impact of 10%% improvement in each factor:\n");
 printf(" Reduce IC by 10%%: New time = %.6f s (%.2f%% faster)\n", 
 new_ic_time, (1 - new_ic_time/cpu_time) * 100);
 printf(" Reduce CPI by 10%%: New time = %.6f s (%.2f%% faster)\n", 
 new_cpi_time, (1 - new_cpi_time/cpu_time) * 100);
 printf(" Increase Rate by 10%%: New time = %.6f s (%.2f%% faster)\n", 
 new_rate_time, (1 - new_rate_time/cpu_time) * 100);
}

int main() {
 // Example from textbook: CPU-A vs CPU-B
 double instruction_count = 1000000; // 1 million instructions

 // CPU-A: 4 GHz, CPI = 1.2
 double cpi_a = 1.2;
 double clock_rate_a = 4e9; // 4 GHz

 // CPU-B: 3 GHz, CPI = 0.9
 double cpi_b = 0.9;
 double clock_rate_b = 3e9; // 3 GHz

 printf("Basic Performance Equation Demo");
 printf("\n================================\n");
 printf("CPU Time = (Instruction Count × CPI) / Clock Rate\n");

 // Compare processors from textbook example
 compare_processors(instruction_count, cpi_a, clock_rate_a, cpi_b, clock_rate_b);

 // Demonstrate weighted CPI with different instruction types
 printf("\n=== Weighted CPI Calculation ===\n");
 double cpi_types[] = {1.0, 1.0, 2.0, 4.0}; // Load, Store, ALU, Branch
 double ic_dist[] = {100000, 200000, 500000, 200000};
 int num_types = 4;

 double weighted_cpi = calculate_weighted_cpi(instruction_count, cpi_types, ic_dist, num_types);
 printf("Instruction Mix: Load=%0.f, Store=%0.f, ALU=%0.f, Branch=%0.f\n",
 ic_dist[0], ic_dist[1], ic_dist[2], ic_dist[3]);
 printf("Weighted Average CPI = %.2f\n", weighted_cpi);

 // Analyze performance bottlenecks
 analyze_bottleneck(instruction_count, cpi_a, clock_rate_a);

 return 0;
}
